@import "tailwindcss";

@keyframes scroll-left {
  from { transform: translateX(0); }
  to { transform: translateX(-50%); }
}

@keyframes hero-left-photo-carousel {
  0%, 50% { opacity: 1; }
  55%, 95% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes fade-in {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes fill-progress {
  from { width: 0%; }
  to { width: 100%; }
}

@keyframes spin-slow {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

.animated-border {
  background: conic-gradient(from 0deg, transparent 30%, var(--color-tertiary) 60%, transparent 70%);
}

.animate-spin-slow {
  animation: spin-slow 4s linear infinite;
}

.link-underline-reveal {
  position: relative;
  text-decoration: none;
}
.link-underline-reveal::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 1px;
  background: currentColor;
  transform-origin: right;
  transform: scaleX(1);
  transition: transform 250ms ease-out;
}
.link-underline-reveal:hover::after {
  animation: link-underline-swipe 500ms cubic-bezier(0.65, 0.05, 0.36, 1);
}
@keyframes link-underline-swipe {
  0% { transform-origin: right; transform: scaleX(1); }
  50% { transform-origin: right; transform: scaleX(0); }
  51% { transform-origin: left; transform: scaleX(0); }
  100% { transform-origin: left; transform: scaleX(1); }
}

.link-underline {
  position: relative;
  text-decoration: none;
}
.link-underline::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 1px;
  background: currentColor;
  transform: scaleX(0);
  transform-origin: right;
  transition: transform 250ms cubic-bezier(0.65, 0.05, 0.36, 1);
}
.link-underline:hover::after {
  transform: scaleX(1);
  transform-origin: left;
}

@theme inline {
  --font-sans: var(--font-inter, "Inter"), system-ui, sans-serif;
  --font-mono: var(--font-dm-mono, "DM Mono"), ui-monospace, monospace;
  --font-display: var(--font-matter), var(--font-inter, "Inter"), system-ui, sans-serif;

  --color-background: #121212;
  --color-surface: oklch(22% 0.004 84.6);
  --color-panel: oklch(29% 0.005 84.6);
  --color-border: oklch(39% 0.006 84.6);
  --color-text: oklch(97% 0.01 84.6);
  --color-text-secondary: oklch(71.5% 0.008 84.6);
  --color-muted: oklch(48% 0.007 84.6);
  --color-accent-purple: #cbb0f7;
  --color-tertiary: #c178ff;
  --color-accent: oklch(72% 0.12 145);

  --space-lg: 1.5rem;
  --shadow: 0 1px 3px rgb(0 0 0 / 0.3), 0 1px 2px rgb(0 0 0 / 0.2);
  --duration-normal: 200ms;

  --radius: 0.125rem;
  --radius-sm: calc(var(--radius) * 0.5);
  --radius-md: var(--radius);
  --radius-lg: calc(var(--radius) * 1.5);
  --radius-xl: calc(var(--radius) * 2);

  --content-max-width: 80rem;
  --scroll-padding-top: 5.25rem;
  --space-section: clamp(4rem, 8vw, 6rem);

  --btn-bg: var(--color-text);
  --btn-border: none;
  --btn-text-color: var(--color-background);
  --btn-padding: 0.25rem 1rem;
  --btn-radius: calc(var(--radius) * 1.5);
  --btn-transform: none;
  --btn-icon-display: none;

  --heading-weight: 400;
  --heading-size: 64px;
  --heading-letter-spacing: -0.025em;
  --body-size: 16px;
  --body-weight: 400;
  --body-line-height: 1.6;

  --img-shadow: 0 8px 30px rgb(0 0 0 / 0.4);
  --img-radius: calc(var(--radius) * 3);
}

html {
  scroll-padding-top: var(--scroll-padding-top);
}

body {
  background-color: var(--color-background);
  color: var(--color-text);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

.font-display {
  font-family: var(--font-display);
}

.animate-scroll-left {
  animation: scroll-left var(--scroll-duration, 40s) linear infinite;
}

.animate-hero-carousel {
  animation: hero-left-photo-carousel 8s infinite;
}

#testimonials {
  --testimonial-bg: var(--color-accent-purple);
  --testimonial-fg: var(--color-background);
  --testimonial-muted: color-mix(in oklch, var(--color-background) 65%, transparent);
}

"use client";

import { useState } from "react";
import Image from "next/image";
import AppleIcon from "./icons/AppleIcon";
import CopyIcon from "./icons/CopyIcon";
import CheckmarkIcon from "./icons/CheckmarkIcon";

const slides = [
  {
    src: "/images/hero-slide-1.jpg",
    alt: "Warp agent prompt and orchestration interface",
    width: 1608,
    height: 1005,
    animationClassName: "animate-[hero-left-photo-carousel_8s_infinite]",
    caption: "Control your cloud agent workforce with central visibility, oversight, and the ability to join agent sessions with a single click.",
  },
  {
    src: "/images/hero-slide-2.jpg",
    alt: "Warp terminal with agentic coding session",
    width: 1800,
    height: 1250,
    animationClassName: "animate-[hero-left-photo-carousel_8s_infinite] [animation-delay:4s]",
    caption: "Build in an open-source agentic development environment born out of the terminal",
  },
];

export default function Hero() {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText("brew install --cask warp");
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // silent fail
    }
  };

  return (
    <section className="py-16" id="home-hero">
      <div className="mx-auto flex w-full max-w-(--content-max-width) flex-col gap-16 px-6 lg:px-10">
        <div className="flex flex-col gap-16">
          <div className="flex flex-col items-start gap-6">
            <h1 className="max-w-5xl text-balance text-[clamp(2.5rem,5vw,var(--heading-size))] leading-[1.1] text-(--color-text) font-display [font-weight:var(--heading-weight)] [letter-spacing:var(--heading-letter-spacing)]">
              Ship better software with any agent
            </h1>
            <div className="flex max-w-3xl flex-col gap-4 text-[calc(var(--body-size)*1.125)] leading-(--body-line-height) text-(--color-text-secondary) font-sans [font-weight:var(--body-weight)]">
              <p>
                Warp is an open agentic development environment born from the terminal. Run coding agents locally and in the cloud, across any model, any harness, repo, or tool.
              </p>
            </div>
            <div className="flex w-full flex-col items-stretch gap-4 sm:w-auto sm:flex-row sm:items-center">
              {/* Download + brew install */}
              <div className="flex w-full items-center rounded-(--btn-radius) bg-(--color-surface) p-1 sm:w-auto">
                <a
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex shrink-0 items-center justify-center gap-1.5 self-stretch rounded-(--btn-radius) rounded-r-none bg-(--btn-bg) px-5 text-sm/7 font-medium text-(--btn-text-color) transition-opacity hover:opacity-85"
                  href="https://app.warp.dev/get_warp?package=dmg"
                >
                  Download
                  <AppleIcon className="inline-block size-4 opacity-90" />
                </a>
                <div className="flex items-center justify-between gap-6 flex-1 self-stretch pl-2 border-0 bg-transparent text-(--color-text-secondary)">
                  <div className="flex items-center gap-2 pl-3">
                    <div className="text-current/60 select-none font-mono text-sm/7">$</div>
                    <span className="font-mono text-sm/7 normal-case tracking-normal">
                      brew install --cask warp
                    </span>
                  </div>
                  <button
                    type="button"
                    onClick={handleCopy}
                    className="group relative flex size-9 items-center justify-center rounded-full after:absolute after:-inset-1 hover:bg-(--color-border) after:pointer-fine:hidden"
                    aria-label="Copy brew install command"
                  >
                    {copied ? <CheckmarkIcon /> : <CopyIcon />}
                  </button>
                </div>
              </div>
              <a
                className="inline-flex shrink-0 items-center justify-center gap-1 rounded-xl bg-text/10 text-sm/7 font-medium text-(--color-text) hover:bg-text/15 transition-colors duration-(--duration-normal) h-11 px-4 py-2 w-full sm:w-auto"
                href="/contact-sales"
              >
                Contact Sales
              </a>
            </div>
          </div>

          {/* Image carousel */}
          <div className="overflow-hidden rounded-xl outline -outline-offset-1 outline-black/5 dark:outline-white/5">
            <div className="relative grid bg-(--color-surface) sm:aspect-16/10">
              {slides.map((slide, i) => (
                <div
                  key={i}
                  className={`col-start-1 row-start-1 opacity-0 sm:absolute sm:inset-0 ${slide.animationClassName}`}
                >
                  <div className="*:block *:h-auto *:w-full sm:size-full sm:*:size-full sm:*:object-cover">
                    <Image
                      src={slide.src}
                      alt={slide.alt}
                      width={slide.width}
                      height={slide.height}
                      quality={90}
                      sizes="100vw"
                      priority={i === 0}
                      className="not-dark:bg-white/75 dark:bg-black/75"
                    />
                  </div>
                  <div className="pointer-events-none bg-black px-4 py-3 sm:absolute sm:right-auto sm:bottom-5 sm:left-5 sm:max-w-[min(32rem,calc(100%-2.5rem))] sm:rounded-lg sm:px-3 sm:py-2">
                    <p className="text-sm/6 font-medium text-white">{slide.caption}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

