167	type ActiveFlyout = "products" | "solutions" | "resources" | "enterprise" | null;
168	
169	export default function Navbar() {
170	  const [activeFlyout, setActiveFlyout] = useState<ActiveFlyout>(null);
171	  const [mobileOpen, setMobileOpen] = useState(false);
172	  const navRef = useRef<HTMLDivElement>(null);
173	  const leaveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
