234	                </button>
235	                {activeFlyout === "products" && (
236	                  <div
237	                    className={`${flyoutPanelBase} ${flyoutSmallWidth}`}
238	                    onMouseEnter={cancelLeave}
239	                    onMouseLeave={scheduleLeave}
240	                  >
241	                    <FlyoutItemProduct item={productsItems[0]} />
242	                    <FlyoutItemProduct item={productsItems[1]} />
243	                    <FlyoutItemProduct item={productsItems[2]} />
244	                  </div>
245	                )}
246	              </div>
247	
248	              {/* Solutions */}
249	              <div
250	                className="relative flex items-center"
251	                onMouseEnter={() => openFlyout("solutions")}
252	                onMouseLeave={scheduleLeave}
253	              >
254	                <button
255	                  onClick={() => toggleFlyout("solutions")}
256	                  className="inline-flex cursor-default items-center gap-1 rounded-lg px-2.5 py-1 text-sm/7 font-medium text-(--color-text) hover:bg-text/5"
257	                >
258	                  Solutions
