260	                </button>
261	                {activeFlyout === "solutions" && (
262	                  <div
263	                    className={`${flyoutPanelBase} ${flyoutSmallWidth}`}
264	                    onMouseEnter={cancelLeave}
265	                    onMouseLeave={scheduleLeave}
266	                  >
267	                    {solutionsItems.map(item => <FlyoutItemRow key={item.label} item={item} />)}
268	                  </div>
269	                )}
270	              </div>
271	
272	              {/* Resources */}
273	              <div
274	                className="relative flex items-center"
275	                onMouseEnter={() => openFlyout("resources")}
276	                onMouseLeave={scheduleLeave}
277	              >
278	                <button
279	                  onClick={() => toggleFlyout("resources")}
280	                  className="inline-flex cursor-default items-center gap-1 rounded-lg px-2.5 py-1 text-sm/7 font-medium text-(--color-text) hover:bg-text/5"
281	                >
282	                  Resources
283	                  <ChevronDownIcon className={`mt-0.5 size-4 opacity-50 transition-transform duration-200 ${activeFlyout === "resources" ? "rotate-180" : ""}`} />
284	                </button>
285	                {activeFlyout === "resources" && (
286	                  <div
287	                    className={`${flyoutPanelBase} ${flyoutWideWidth}`}
288	                    onMouseEnter={cancelLeave}
289	                    onMouseLeave={scheduleLeave}
290	                  >
291	                    <div className="flex divide-x divide-(--color-border) p-2 *:flex-1 [&>*:first-child]:pr-4 [&>*:not(:first-child)]:pl-4">
292	                      <div className="min-w-44">
