308	                            <FlyoutItemRow key={item.label} item={item} hoverOnWrapper />
309	                          ))}
310	                        </div>
311	                      </div>
312	                    </div>
313	                  </div>
314	                )}
315	              </div>
316	
317	              {/* Enterprise */}
318	              <div
319	                className="relative flex items-center"
320	                onMouseEnter={() => openFlyout("enterprise")}
321	                onMouseLeave={scheduleLeave}
322	              >
323	                <button
324	                  onClick={() => toggleFlyout("enterprise")}
325	                  className="inline-flex cursor-default items-center gap-1 rounded-lg px-2.5 py-1 text-sm/7 font-medium text-(--color-text) hover:bg-text/5"
326	                >
327	                  Enterprise
