359	                className="inline-flex items-center font-medium h-8.75 gap-2 rounded-lg px-3 text-sm/6 text-(--color-text) transition-colors duration-(--duration-normal) hover:bg-text/10 focus-visible:bg-text/10 max-lg:hidden"
360	                aria-label="Star Warp on GitHub (60,013 stars)"
