367	                className="inline-flex shrink-0 items-center justify-center gap-2 rounded-(--radius-xl) text-sm/7 font-medium text-(--color-text) transition-colors duration-(--duration-normal) hover:bg-text/10 h-9 px-3 py-1 max-lg:hidden"
368	                href="/contact-sales"
369	              >
370	                Contact sales
371	              </a>
372	              <a
373	                className="inline-flex h-8.75 shrink-0 items-center justify-center gap-1.5 rounded-(--btn-radius) bg-(--btn-bg) p-(--btn-padding) text-sm/7 font-medium text-(--btn-text-color) transition-opacity [border:var(--btn-border)] hover:opacity-85"
374	                href="https://app.warp.dev/get_warp?package=dmg"
375	                target="_blank"
376	                rel="noopener noreferrer"
377	              >
378	                Download
379	                <AppleIcon className="inline-block size-4 opacity-90" />
380	                <kbd className="ml-1 inline-flex size-5 items-center justify-center rounded bg-current/10 text-[11px] font-semibold uppercase opacity-60">D</kbd>
381	              </a>
382	            </div>
383	
384	            {/* Hamburger */}
385	            <button
386	              onClick={() => setMobileOpen(true)}
387	              aria-label="Toggle menu"
388	              className="inline-flex rounded-full p-1.5 text-(--color-text) hover:bg-text/10 lg:hidden"
389	            >
390	              <HamburgerIcon className="size-6" />
391	            </button>
392	          </div>
393	        </div>
394	
395	        {/* Mobile menu */}
396	        {mobileOpen && (
397	          <div className="fixed inset-0 z-9999 flex flex-col overflow-y-auto bg-(--color-background) px-6 py-6 lg:hidden lg:px-10">
398	            <div className="flex justify-end">
399	              <button
400	                onClick={() => setMobileOpen(false)}
401	                aria-label="Close menu"
402	                className="inline-flex rounded-full p-1.5 text-(--color-text) hover:bg-text/10"
403	              >
404	                <XMarkIcon className="size-6" />
405	              </button>
406	            </div>
407	            <div className="mt-6 flex min-h-0 flex-1 flex-col gap-6">
408	              <details className="group">
409	                <summary className="flex cursor-pointer list-none items-center justify-between text-3xl/10 font-medium text-(--color-text)">
410	                  Products<ChevronDownLgIcon className="size-5 opacity-50 transition-transform group-open:rotate-180" />
411	                </summary>
412	                <div className="mt-4 flex flex-col gap-1 pl-1">
413	                  {productsItems.map(item => <FlyoutItemProduct key={item.label} item={item} />)}
414	                </div>
415	              </details>
416	              <details className="group">
417	                <summary className="flex cursor-pointer list-none items-center justify-between text-3xl/10 font-medium text-(--color-text)">
418	                  Solutions<ChevronDownLgIcon className="size-5 opacity-50 transition-transform group-open:rotate-180" />
